const fs = require('fs');
const path = require('path');

const outFile = path.join(__dirname, '..', 'src', 'data', 'comentariosExpandidosNovos.ts');

let content = fs.readFileSync(outFile, 'utf8');

function addEntry(livro, cap, v, titulo, resumo, comments, refs) {
  const cLines = comments.map(c => {
    let s = `    { teologo: '${c[0]}', periodo: '${c[1]}', tradicao: '${c[2]}', texto: '${c[3]}', obra: '${c[4]}'`;
    if (c[5]) s += `, ano: ${c[5]}`;
    s += ' }';
    return s;
  }).join(',\n');
  const refStr = refs ? `\n  ${JSON.stringify(refs)}` : '';
  content += `add('${livro}', ${cap}, ${v}, '${titulo}',\n  '${resumo}',\n  [\n${cLines},\n  ]${refStr});\n\n`;
}

